/**
 * Rasterize an OG SVG to a 1200×630 PNG via @resvg/resvg-js.
 *
 * Fonts are loaded from the vendored subsets at `assets/fonts/og/`. These
 * subsets are regenerated by `scripts/build-og-fonts.mjs` when the content
 * corpus changes, so the build is offline-safe and reproducible.
 */

import { readFileSync, existsSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';
import { createHash } from 'node:crypto';

import { Resvg } from '@resvg/resvg-js';

const __dirname = dirname(fileURLToPath(import.meta.url));
const FONTS_DIR = join(__dirname, '..', '..', 'assets', 'fonts', 'og');

const FONT_FILES = [
  'NotoSerifSC-subset.ttf',
  'EBGaramond-subset.ttf',
  'Inconsolata-subset.ttf'
];

let fontBuffersCache = null;

function loadFontBuffers() {
  if (fontBuffersCache) return fontBuffersCache;
  const buffers = [];
  for (const name of FONT_FILES) {
    const p = join(FONTS_DIR, name);
    if (!existsSync(p)) {
      throw new Error(`OG font missing: ${p}. Run: node scripts/build-og-fonts.mjs`);
    }
    buffers.push(readFileSync(p));
  }
  fontBuffersCache = buffers;
  return buffers;
}

/**
 * Rasterize an SVG string to a 1200×630 PNG buffer.
 */
export function rasterizeOgSvg(svg) {
  const fontBuffers = loadFontBuffers();
  const r = new Resvg(svg, {
    fitTo: { mode: 'width', value: 1200 },
    background: '#f2e8d5',
    font: {
      loadSystemFonts: false,
      fontBuffers,
      defaultFontFamily: 'Noto Serif SC'
    }
  });
  return r.render().asPng();
}

/**
 * Stable content hash for caching: identifies a (svg, font-corpus) pair.
 * If either changes, the hash changes and the PNG is regenerated.
 */
let fontCorpusHash = null;
function getFontCorpusHash() {
  if (fontCorpusHash) return fontCorpusHash;
  const h = createHash('sha256');
  for (const buf of loadFontBuffers()) h.update(buf);
  fontCorpusHash = h.digest('hex').slice(0, 16);
  return fontCorpusHash;
}

export function ogContentHash(svg) {
  return createHash('sha256').update(svg).update(getFontCorpusHash()).digest('hex').slice(0, 16);
}
